import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as n,o as i,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Google Drive Channel যোগ করা","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/upload/google-drive.md","filePath":"bn-BD/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"bn-BD/upload/google-drive.md"};function c(p,e,h,g,u,m){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="google-drive-channel-যোগ-করা" tabindex="-1">Google Drive Channel যোগ করা <a class="header-anchor" href="#google-drive-channel-যোগ-করা" aria-label="Permalink to &quot;Google Drive Channel যোগ করা&quot;">​</a></h1><h2 id="আগে-যা-লাগবে" tabindex="-1">আগে যা লাগবে <a class="header-anchor" href="#আগে-যা-লাগবে" aria-label="Permalink to &quot;আগে যা লাগবে&quot;">​</a></h2><p>শুরু করার আগে এগুলো প্রস্তুত রাখুন:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>কেন লাগবে</th></tr></thead><tbody><tr><td>Google account</td><td>Google Cloud access এবং Google Drive authorize করতে লাগে</td></tr><tr><td>Google Cloud project</td><td>Drive API enable এবং OAuth credentials তৈরি করতে লাগে</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed <code>Client ID</code>, <code>Client Secret</code> এবং <code>Refresh Token</code> নিতে এটি ব্যবহার করে</td></tr><tr><td>আপনার ImgBed domain</td><td>OAuth redirect URI-এর জন্য লাগে। আপনি যে domain ব্যবহার করেন সেটির সঙ্গে match করতে হবে।</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-google-drive-api-enable-করুন" tabindex="-1">Step 1: Google Drive API Enable করুন <a class="header-anchor" href="#step-1-google-drive-api-enable-করুন" aria-label="Permalink to &quot;Step 1: Google Drive API Enable করুন&quot;">​</a></h3><ol><li>Google Cloud Console খুলুন।</li><li>নতুন project তৈরি করুন অথবা existing project নির্বাচন করুন।</li><li><code>APIs &amp; Services</code>-এ যান।</li><li><code>Enable APIs and Services</code> ক্লিক করুন।</li><li><code>Google Drive API</code> search করুন।</li><li>খুলে enable ক্লিক করুন।</li></ol><h3 id="step-2-oauth-consent-screen-configure-করুন" tabindex="-1">Step 2: OAuth Consent Screen Configure করুন <a class="header-anchor" href="#step-2-oauth-consent-screen-configure-করুন" aria-label="Permalink to &quot;Step 2: OAuth Consent Screen Configure করুন&quot;">​</a></h3><ol><li>Google Cloud-এ <code>Google Auth Platform</code> খুলুন।</li><li>App name, support email এবং developer contact email-এর মতো basic <code>Branding</code> information পূরণ করুন।</li><li><code>Audience</code> খুলুন।</li><li>বেশিরভাগ self-hosted personal deployment-এর জন্য <code>External</code> নির্বাচন করুন।</li><li><code>External</code> নির্বাচন করলে যে Google account authorize করতে চান সেটি <code>Test users</code>-এ যোগ করুন।</li><li><code>Data Access</code> খুলুন।</li><li>প্রয়োজনীয় Google Drive permissions যোগ করুন।</li></ol><h3 id="step-3-oauth-2-0-client-তৈরি-করুন" tabindex="-1">Step 3: OAuth 2.0 Client তৈরি করুন <a class="header-anchor" href="#step-3-oauth-2-0-client-তৈরি-করুন" aria-label="Permalink to &quot;Step 3: OAuth 2.0 Client তৈরি করুন&quot;">​</a></h3><ol><li><code>Google Auth Platform</code>-এ <code>Clients</code> খুলুন।</li><li>নতুন client তৈরি করুন।</li><li>Application type <code>Web application</code> সেট করুন।</li><li>Client-এর চেনা যায় এমন নাম দিন।</li><li>Authorized JavaScript origins-এ আপনার ImgBed URL দিন, যেমন:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Authorized redirect URIs-এ দিন:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Enter domain and callback URL" loading="lazy"></p><p>Client তৈরি হলে এই values copy করুন:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-google-drive-channel-পূরণ-করুন" tabindex="-1">Step 4: Google Drive Channel পূরণ করুন <a class="header-anchor" href="#step-4-google-drive-channel-পূরণ-করুন" aria-label="Permalink to &quot;Step 4: Google Drive Channel পূরণ করুন&quot;">​</a></h2><p>Upload Settings-এ <code>Google Drive</code> নির্বাচন করে পূরণ করুন:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>কী দেবেন</th></tr></thead><tbody><tr><td>Channel name</td><td>চেনা যায় এমন নাম, যেমন <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Google Cloud থেকে পাওয়া Client ID</td></tr><tr><td>Client Secret</td><td>Google Cloud থেকে পাওয়া Client Secret</td></tr><tr><td>Refresh Token</td><td>আপাতত empty রাখুন। পরের step-এ নেবেন।</td></tr><tr><td>Root directory</td><td>Optional। Default <code>imgbed</code>।</td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-refresh-token-নিন" tabindex="-1">Step 5: Refresh Token নিন <a class="header-anchor" href="#step-5-refresh-token-নিন" aria-label="Permalink to &quot;Step 5: Refresh Token নিন&quot;">​</a></h2><ol><li><code>Get Token</code> ক্লিক করুন।</li><li>যে Google account connect করতে চান সেটি নির্বাচন করুন।</li><li>Authorization prompts complete করুন।</li><li>Callback page একটি <code>Refresh Token</code> দেখাবে।</li><li>সেটি copy করুন।</li><li>ImgBed-এ ফিরে <code>Refresh Token</code> field-এ paste করুন।</li></ol><p><img src="'+l+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>পরে Google account বদলালে, OAuth client বদলালে, বা পুরোনো authorization expire হলে channel delete করার দরকার নেই। Edit page খুলে <code>Reauthorize</code> ক্লিক করুন।</p><h2 id="step-6-channel-save-করুন" tabindex="-1">Step 6: Channel Save করুন <a class="header-anchor" href="#step-6-channel-save-করুন" aria-label="Permalink to &quot;Step 6: Channel Save করুন&quot;">​</a></h2><p>সব fields পূরণ হলে channel save করুন।</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Cloud খুলুন</span></span>
<span class="line"><span>-&gt; Project create বা select করুন</span></span>
<span class="line"><span>-&gt; Google Drive API enable করুন</span></span>
<span class="line"><span>-&gt; Google Auth Platform configure করুন</span></span>
<span class="line"><span>-&gt; Audience External হলে আপনার Google account Test users-এ যোগ করুন</span></span>
<span class="line"><span>-&gt; Web application OAuth client তৈরি করুন</span></span>
<span class="line"><span>-&gt; Redirect URI হিসেবে https://your-domain.com/api/oauth/google/callback ব্যবহার করুন</span></span>
<span class="line"><span>-&gt; ImgBed-এ Client ID এবং Client Secret পূরণ করুন</span></span>
<span class="line"><span>-&gt; Get Token ক্লিক করুন</span></span>
<span class="line"><span>-&gt; Google দিয়ে sign in করে authorize করুন</span></span>
<span class="line"><span>-&gt; Callback page থেকে Refresh Token copy করুন</span></span>
<span class="line"><span>-&gt; ImgBed-এ paste করে save করুন</span></span>
<span class="line"><span>-&gt; Test image upload করুন</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const k=n(d,[["render",c]]);export{f as __pageData,k as default};
